            <div class="d-flex flex-column gap-2 mt-3">
                <button class="btn btn-primary" @onclick="ApplyFiltersAsync">Apply Filters</button>
                <button class="btn btn-outline-secondary" @onclick="ClearFiltersAsync">Clear Filters</button>
            </div>
        </aside>

        <!-- Main Content -->
        <main class="catalog-main">
            <!-- Toolbar -->
            <div class="catalog-toolbar">
                <div class="d-flex align-items-center gap-3">
                    <label class="form-label mb-0 text-nowrap" for="sortSelect">Sort by:</label>
                    <select id="sortSelect" class="form-select form-select-sm w-auto" @bind="sortBy" @bind:after="SortChangedAsync">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                @if (result is not null && result.TotalCount > 0)
                {
                    var first = (result.Page - 1) * result.PageSize + 1;
                    var last = Math.Min(result.Page * result.PageSize, result.TotalCount);
                    <span class="text-muted">Showing @first–@last of @result.TotalCount products</span>
                }
            </div>

            <!-- Product Grid -->
            @if (isLoading)
            {
                <div class="d-flex justify-content-center align-items-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                </div>
            }
            else if (result is null || result.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <h5 class="text-muted">No products found</h5>
                    <p class="text-muted">Try adjusting your filters.</p>
                </div>
            }
            else
            {
                <div class="product-grid">
                    @foreach (var product in result.Items)
                    {
                        <ProductCard Product="product" OnProductSelected="HandleProductSelected" OnAddToCart="HandleAddToCart" />
                    }
                </div>

                <!-- Pagination -->
                @{
                    var totalPages = (int)Math.Ceiling((double)result.TotalCount / result.PageSize);
                }
                @if (totalPages > 1)
                {
                    <nav aria-label="Product pagination" class="mt-4">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(currentPage <= 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(currentPage - 1)" disabled="@(currentPage <= 1)">Previous</button>
                            </li>
                            @for (var i = 1; i <= totalPages; i++)
                            {
                                var pageNum = i;
                                <li class="page-item @(pageNum == currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(pageNum)">@pageNum</button>
                                </li>
                            }
                            <li class="page-item @(currentPage >= totalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(currentPage + 1)" disabled="@(currentPage >= totalPages)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </main>
    </div>
}

@code {
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? result;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProductsAsync();

            categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load catalog: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchProductsAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to search products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFiltersAsync()
    {
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task ClearFiltersAsync()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task SortChangedAsync()
    {
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task GoToPageAsync(int page)
    {
        currentPage = page;
        await SearchProductsAsync();
    }

    private async Task RetryAsync()
    {
        await LoadDataAsync();
    }

    private void HandleProductSelected(Product product)
    {
        // Parent-level navigation hook; extend as needed
    }

    private void HandleAddToCart(Product product)
    {
        // Add-to-cart handling; extend as needed
    }
}

