toolArgs.file_text:
@using sv_f5b6ddc7290f4c649741565aa6f419fe.Services

<div class="product-card" @onclick="OnCardClick" role="button" tabindex="0">
    <div class="product-image" title="@Product.Name">
        <span>@Product.Name</span>
    </div>

    <div class="product-info">
        <h6 class="product-name" title="@Product.Name">@Product.Name</h6>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <div class="product-rating" title="@($"{Product.Rating:F1} out of 5")">
            @GetStarDisplay(Product.Rating)
        </div>

        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }

        <button class="btn btn-sm btn-success w-100"
                disabled="@(!Product.InStock)"
                @onclick="OnAddToCartClick"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
